import fs from 'fs';
import path from 'path';

const RNFS = {
    DocumentDirectoryPath: path.join(process.cwd(), 'vine_images'),
    writeFile: async (p, c) => fs.writeFileSync(p, c, 'ascii'),
    appendFile: async (p, c) => fs.appendFileSync(p, c, 'ascii'),
    exists: async (p) => fs.existsSync(p),
    unlink: async (p) => fs.unlinkSync(p),
    read: async (p, l, pos) => {
        const fd = fs.openSync(p, 'r');
        const buf = Buffer.alloc(l);
        fs.readSync(fd, buf, 0, l, pos);
        fs.closeSync(fd);
        return buf.toString('base64');
    },
    write: async (p, b64, pos) => {
        const fd = fs.openSync(p, 'r+');
        const buf = Buffer.from(b64, 'base64');
        fs.writeSync(fd, buf, 0, buf.length, pos);
        fs.closeSync(fd);
    }
};

export default RNFS;
